#include <stdio.h>
#include <string.h>
#define MOD 1000000007

int main() {
    int T;
    if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        char s[1005];
        scanf("%s", s);
        int n = strlen(s);
        static int isPal[1000][1000];
        // pre‑compute palindromes
        for (int i = 0; i < n; ++i) {
            isPal[i][i] = 1;
        }
        for (int len = 2; len <= n; ++len) {
            for (int i = 0; i + len - 1 < n; ++i) {
                int j = i + len - 1;
                if (s[i] == s[j]) {
                    if (len == 2) isPal[i][j] = 1;
                    else isPal[i][j] = isPal[i+1][j-1];
                } else {
                    isPal[i][j] = 0;
                }
            }
        }
        long long dp[1005] = {0};
        dp[0] = 1;
        for (int i = 1; i <= n; ++i) {
            long long sum = 0;
            for (int j = 0; j < i; ++j) {
                if (isPal[j][i-1]) {
                    sum += dp[j];
                    if (sum >= MOD) sum -= MOD;
                }
            }
            dp[i] = sum;
        }
        printf("%lld\n", dp[n] % MOD);
    }
    return 0;
}

