import sys
MOD = 1_000_000_007

def count_pal(s: str) -> int:
    n = len(s)
    pal = [[False] * n for _ in range(n)]
    for i in range(n):
        pal[i][i] = True
    for length in range(2, n + 1):
        for i in range(n - length + 1):
            j = i + length - 1
            if s[i] == s[j]:
                if length == 2:
                    pal[i][j] = True
                else:
                    pal[i][j] = pal[i + 1][j - 1]
    dp = [0] * (n + 1)
    dp[0] = 1
    for i in range(1, n + 1):
        total = 0
        for j in range(i):
            if pal[j][i - 1]:
                total += dp[j]
                if total >= MOD:
                    total -= MOD
        dp[i] = total % MOD
    return dp[n]

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T + 1):
        out.append(str(count_pal(data[i].strip())))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

